// Tricorn (Mandelbar) degree 4: z_{n+1} = conj(z)^4 + c.
// The conjugation before squaring breaks holomorphicity, producing
// a set with 4-fold anti-holomorphic symmetry. The boundary is not
// smooth — it has cusp-like features at every period-doubling bifurcation.
// Unlike the quadratic Tricorn (z̄²+c), degree-4 produces 3 primary
// "antennas" per arm. Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
uniform float uColorScheme;
uniform float uTransparentBg;

