vec2 cpow2(vec2 z) { return cmul(z,z); }
vec2 cpow3(vec2 z) { return cmul(cpow2(z), z); }
vec2 cexp(vec2 z) {
  float ex = exp(clamp(z.x, -40.0, 40.0));
